/**
 * Cooperation Invariants System - Type Definitions
 *
 * Implements a contract over observable relations with invariants:
 * - T (transparency): How transparent is the cooperation
 * - V (verifiability): How verifiable are the claims
 * - F (freedom): How free is participation
 * - C (capacity): What's the cooperation capacity
 */

/**
 * Current state of cooperation invariants
 * All values are on a 0-1 scale
 */
export interface InvariantState {
  transparency: number;
  verifiability: number;
  freedom: number;
  capacity: number;
  timestamp: Date;
}

/**
 * Changes in invariants (ΔT, ΔV, ΔF, ΔC)
 * Positive values indicate improvement
 */
export interface InvariantDelta {
  deltaT: number;
  deltaV: number;
  deltaF: number;
  deltaC: number;
  /** Whether all deltas satisfy the commitment rule (Δ≥0) */
  satisfaction: 'all-positive' | 'partial' | 'violated';
}

/**
 * Action with estimated and actual invariant impacts
 */
export interface CooperationAction {
  id: string;
  type: string;
  actor: string;
  localContext: string;
  timestamp: Date;
  estimatedImpact: InvariantDelta;
  actualImpact?: InvariantDelta;
  outcome: 'success' | 'failure' | 'pending';
  /** Observable facts supporting locality of this action */
  observableFacts?: string[];
}

/**
 * Result of commitment rule validation
 * Rule: ΔT≥0 ∧ ΔV≥0 ∧ ΔF≥0 ∧ ΔC≥0
 */
export interface CommitmentResult {
  satisfied: boolean;
  violatedInvariants: ('T' | 'V' | 'F' | 'C')[];
  recommendation: string;
}

/**
 * Result of locality validation
 * Locality condition: Only claim what is locally observable
 */
export interface LocalityResult {
  valid: boolean;
  errors: string[];
  warnings: string[];
  localityCompliant: boolean;
}

/**
 * Combined validation result
 */
export interface ValidationResult {
  commitment: CommitmentResult;
  locality: LocalityResult;
  overallValid: boolean;
}

/**
 * Log entry format for JSONL storage
 */
export interface CooperationLogEntry {
  action: CooperationAction;
  validation: ValidationResult;
  stateBefore: InvariantState;
  stateAfter: InvariantState;
  loggedAt: Date;
}

/**
 * Cooperation Invariants System - Core Tracker
 *
 * Tracks invariant states and calculates deltas between states.
 */

import type {
  InvariantState,
  InvariantDelta,
  CooperationAction
} from './types.js';

/**
 * Default initial state for all invariants
 */
const DEFAULT_STATE: InvariantState = {
  transparency: 0.5,
  verifiability: 0.5,
  freedom: 0.5,
  capacity: 0.5,
  timestamp: new Date()
};

/**
 * Tracks cooperation invariants over time
 */
export class InvariantTracker {
  private currentState: InvariantState;
  private actionHistory: CooperationAction[] = [];

  constructor(initialState?: InvariantState) {
    this.currentState = initialState ?? { ...DEFAULT_STATE };
  }

  /**
   * Record an action and update state based on actual impact
   */
  recordAction(action: CooperationAction): void {
    this.actionHistory.push(action);

    if (action.actualImpact) {
      this.applyDelta(action.actualImpact);
    }

    this.currentState.timestamp = new Date();
  }

  /**
   * Get current invariant state
   */
  getCurrentState(): InvariantState {
    return { ...this.currentState };
  }

  /**
   * Calculate delta between two states
   */
  getDelta(before: InvariantState, after: InvariantState): InvariantDelta {
    const deltaT = after.transparency - before.transparency;
    const deltaV = after.verifiability - before.verifiability;
    const deltaF = after.freedom - before.freedom;
    const deltaC = after.capacity - before.capacity;

    const satisfaction = this.determineSatisfaction(deltaT, deltaV, deltaF, deltaC);

    return { deltaT, deltaV, deltaF, deltaC, satisfaction };
  }

  /**
   * Calculate delta for an action's estimated impact
   */
  estimateDelta(action: CooperationAction): InvariantDelta {
    const current = this.getCurrentState();
    const estimated: InvariantState = {
      transparency: current.transparency + action.estimatedImpact.deltaT,
      verifiability: current.verifiability + action.estimatedImpact.deltaV,
      freedom: current.freedom + action.estimatedImpact.deltaF,
      capacity: current.capacity + action.estimatedImpact.deltaC,
      timestamp: new Date()
    };

    return this.getDelta(current, estimated);
  }

  /**
   * Get action history
   */
  getHistory(): CooperationAction[] {
    return [...this.actionHistory];
  }

  /**
   * Reset to initial state
   */
  reset(): void {
    this.currentState = { ...DEFAULT_STATE };
    this.actionHistory = [];
  }

  /**
   * Apply a delta to the current state
   */
  private applyDelta(delta: InvariantDelta): void {
    this.currentState.transparency = this.clamp(
      this.currentState.transparency + delta.deltaT
    );
    this.currentState.verifiability = this.clamp(
      this.currentState.verifiability + delta.deltaV
    );
    this.currentState.freedom = this.clamp(
      this.currentState.freedom + delta.deltaF
    );
    this.currentState.capacity = this.clamp(
      this.currentState.capacity + delta.deltaC
    );
  }

  /**
   * Clamp value to [0, 1] range
   */
  private clamp(value: number): number {
    return Math.max(0, Math.min(1, value));
  }

  /**
   * Determine satisfaction level from delta values
   */
  private determineSatisfaction(
    deltaT: number,
    deltaV: number,
    deltaF: number,
    deltaC: number
  ): InvariantDelta['satisfaction'] {
    const allPositive = deltaT >= 0 && deltaV >= 0 && deltaF >= 0 && deltaC >= 0;
    const anyPositive = deltaT > 0 || deltaV > 0 || deltaF > 0 || deltaC > 0;

    if (allPositive) return 'all-positive';
    if (anyPositive) return 'partial';
    return 'violated';
  }
}

/**
 * Cooperation Invariants System - Validators
 *
 * Validates commitment rule and locality condition.
 */

import type {
  InvariantDelta,
  CooperationAction,
  CommitmentResult,
  LocalityResult,
  ValidationResult
} from './types.js';

/**
 * Validate the commitment rule: ΔT≥0 ∧ ΔV≥0 ∧ ΔF≥0 ∧ ΔC≥0
 * "Do not reduce transparency, verifiability, freedom, or cooperation capacity."
 */
export function validateCommitment(delta: InvariantDelta): CommitmentResult {
  const violatedInvariants: ('T' | 'V' | 'F' | 'C')[] = [];

  if (delta.deltaT < 0) violatedInvariants.push('T');
  if (delta.deltaV < 0) violatedInvariants.push('V');
  if (delta.deltaF < 0) violatedInvariants.push('F');
  if (delta.deltaC < 0) violatedInvariants.push('C');

  const satisfied = violatedInvariants.length === 0;
  const recommendation = satisfied
    ? 'Action is cooperation-compliant: all invariants preserved or improved.'
    : `Reject action: violates ${violatedInvariants.join(', ')} invariants. Cooperation requires Δ≥0 for all invariants.`;

  return { satisfied, violatedInvariants, recommendation };
}

/**
 * Validate the locality condition: "Only claim what is locally observable."
 * Ensures actions are grounded in local, verifiable facts.
 */
export function validateLocality(action: CooperationAction): LocalityResult {
  const errors: string[] = [];
  const warnings: string[] = [];

  // Check local context is specified
  if (!action.localContext || action.localContext.trim() === '') {
    errors.push('Missing local context identifier. Locality requires a specific context.');
  }

  // Check for observable facts
  if (!action.observableFacts || action.observableFacts.length === 0) {
    warnings.push('No observable facts provided. Action may not be verifiable by others.');
  }

  // Check for non-local claims (simple heuristic: claims about "everyone", "always", etc.)
  const nonLocalKeywords = ['everyone', 'always', 'never', 'universal', 'absolute', 'global'];
  const combinedText = `${action.type} ${action.localContext} ${(action.observableFacts ?? []).join(' ')}`;
  const foundNonLocalClaims = nonLocalKeywords.filter(kw =>
    combinedText.toLowerCase().includes(kw)
  );

  if (foundNonLocalClaims.length > 0) {
    errors.push(
      `Detected potentially non-local claims using: ${foundNonLocalClaims.join(', ')}. ` +
      'Locality condition requires claims to be about observable, specific contexts.'
    );
  }

  // Validate facts are non-empty
  if (action.observableFacts) {
    const emptyFacts = action.observableFacts.filter(f => !f || f.trim() === '');
    if (emptyFacts.length > 0) {
      warnings.push(`${emptyFacts.length} observable fact(s) are empty.`);
    }
  }

  const valid = errors.length === 0;
  const localityCompliant = valid;

  return { valid, errors, warnings, localityCompliant };
}

/**
 * Validate both commitment rule and locality condition
 */
export function validateAction(
  action: CooperationAction
): ValidationResult {
  const commitment = validateCommitment(action.estimatedImpact);
  const locality = validateLocality(action);

  const overallValid = commitment.satisfied && locality.valid;

  return { commitment, locality, overallValid };
}

/**
 * Check if invariant values are within valid range [0, 1]
 */
export function validateInvariantRange(
  transparency: number,
  verifiability: number,
  freedom: number,
  capacity: number
): boolean {
  const inRange = (v: number) => v >= 0 && v <= 1;
  return inRange(transparency) && inRange(verifiability) && inRange(freedom) && inRange(capacity);
}

/**
 * Cooperation Invariants System - Basic Usage Example
 *
 * Demonstrates tracking cooperation invariants and validating
 * the commitment rule and locality condition.
 */

import { InvariantTracker } from '../core/InvariantTracker.js';
import {
  validateAction,
  validateCommitment,
  validateLocality
} from '../core/validators.js';
import type {
  CooperationAction,
  InvariantDelta
} from '../core/types.js';

/**
 * Create a cooperation action with invariant impacts
 */
function createAction(
  id: string,
  type: string,
  localContext: string,
  deltaT: number,
  deltaV: number,
  deltaF: number,
  deltaC: number,
  observableFacts?: string[]
): CooperationAction {
  const impact: InvariantDelta = {
    deltaT,
    deltaV,
    deltaF,
    deltaC,
    satisfaction: 'all-positive'
  };

  return {
    id,
    type,
    actor: 'system',
    localContext,
    timestamp: new Date(),
    estimatedImpact: impact,
    outcome: 'success',
    observableFacts
  };
}

/**
 * Print validation results
 */
function printValidation(action: CooperationAction): void {
  console.log(`\n=== Action: ${action.type} ===`);
  console.log(`Context: ${action.localContext}`);
  console.log(`Impact: ΔT=${action.estimatedImpact.deltaT}, ΔV=${action.estimatedImpact.deltaV}, ΔF=${action.estimatedImpact.deltaF}, ΔC=${action.estimatedImpact.deltaC}`);

  const validation = validateAction(action);

  console.log(`\nCommitment Rule:`);
  console.log(`  Satisfied: ${validation.commitment.satisfied}`);
  console.log(`  ${validation.commitment.recommendation}`);

  console.log(`\nLocality Condition:`);
  console.log(`  Valid: ${validation.locality.valid}`);
  if (validation.locality.errors.length > 0) {
    console.log(`  Errors: ${validation.locality.errors.join('; ')}`);
  }
  if (validation.locality.warnings.length > 0) {
    console.log(`  Warnings: ${validation.locality.warnings.join('; ')}`);
  }

  console.log(`\nOverall: ${validation.overallValid ? '✅ VALID' : '❌ INVALID'}`);
}

/**
 * Print current tracker state
 */
function printState(tracker: InvariantTracker): void {
  const state = tracker.getCurrentState();
  console.log('\n--- Current Invariant State ---');
  console.log(`Transparency (T):  ${state.transparency.toFixed(2)}`);
  console.log(`Verifiability (V): ${state.verifiability.toFixed(2)}`);
  console.log(`Freedom (F):      ${state.freedom.toFixed(2)}`);
  console.log(`Capacity (C):     ${state.capacity.toFixed(2)}`);
}

/**
 * Main demonstration
 */
async function main(): Promise<void> {
  console.log('=== Cooperation Invariants System - Basic Usage ===\n');

  // Initialize tracker
  const tracker = new InvariantTracker();
  printState(tracker);

  // Example 1: Valid cooperative action (all deltas positive)
  console.log('\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━');
  const action1 = createAction(
    'action-1',
    'publish-open-source',
    'project-kiss',
    0.2,  // Increases transparency
    0.1,  // Increases verifiability
    0.0,  // Maintains freedom
    0.1,  // Increases capacity
    ['code-released-to-public', 'license-visible-to-all']
  );
  printValidation(action1);

  if (validateAction(action1).overallValid) {
    tracker.recordAction(action1);
  }
  printState(tracker);

  // Example 2: Valid action (maintains invariants)
  console.log('\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━');
  const action2 = createAction(
    'action-2',
    'add-documentation',
    'project-kiss',
    0.1,  // Increases transparency
    0.0,  // Maintains verifiability
    0.0,  // Maintains freedom
    0.0,  // Maintains capacity
    ['readme-file-updated']
  );
  printValidation(action2);

  if (validateAction(action2).overallValid) {
    tracker.recordAction(action2);
  }
  printState(tracker);

  // Example 3: Invalid action (violates commitment rule - reduces freedom)
  console.log('\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━');
  const action3 = createAction(
    'action-3',
    'restrict-participation',
    'project-kiss',
    -0.1, // Reduces transparency
    0.0,  // Maintains verifiability
    -0.2, // Reduces freedom
    0.1,  // Increases capacity
    ['access-control-added']
  );
  printValidation(action3);

  if (validateAction(action3).overallValid) {
    tracker.recordAction(action3);
  } else {
    console.log('\n⚠️  Action rejected due to invariant violations.');
  }
  printState(tracker);

  // Example 4: Invalid action (violates locality - no observable facts)
  console.log('\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━');
  const action4 = createAction(
    'action-4',
    'claim-universal-truth',
    'abstract-concept',
    0.5,
    0.5,
    0.5,
    0.5,
    [] // No observable facts - locality violation
  );
  printValidation(action4);

  if (validateAction(action4).overallValid) {
    tracker.recordAction(action4);
  } else {
    console.log('\n⚠️  Action rejected due to locality violations.');
  }
  printState(tracker);

  // Summary
  console.log('\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━');
  console.log('=== Summary ===');
  const history = tracker.getHistory();
  console.log(`Total actions recorded: ${history.length}`);
  console.log(`Valid actions: ${history.length}`);
  console.log(`Rejected actions: 2 (commitment violation, locality violation)');

  console.log('\n=== Framework Summary ===');
  console.log('Commitment Rule: ΔT≥0 ∧ ΔV≥0 ∧ ΔF≥0 ∧ ΔC≥0');
  console.log('Locality Condition: Only claim what is locally observable');
  console.log('\n"Reality as a network, not a throne."');
  console.log('Nodes gain influence by becoming observable, predictable, and cooperative.');
}

// Run the example
main().catch(console.error);

/**
