/**
 * Bottom-Up Cooperation Simulation - Agent
 *
 * Minimal agent with simple rules. Observations come from behavior.
 */

export interface AgentState {
  resources: number;
  alive: boolean;
}

export interface Action {
  type: 'gather' | 'share' | 'keep' | 'observe';
  amount: number;
  target?: string; // agent id
}

export interface Observation {
  observer: string;
  observed: string;
  action: Action;
  timestamp: number;
}

/**
 * Minimal agent with simple goals
 */
export class Agent {
  id: string;
  state: AgentState;
  memory: Observation[] = [];

  constructor(id: string, initialResources: number = 10) {
    this.id = id;
    this.state = {
      resources: initialResources,
      alive: initialResources > 0
    };
  }

  /**
   * Decide what to do based on current state
   * Minimal rules: survive if possible, help if affordable
   */
  decide(context: {
    selfState: AgentState;
    others: Map<string, AgentState>;
    step: number;
  }): Action {
    const { selfState, others, step } = context;

    // If starving, keep resources
    if (selfState.resources < 2) {
      return { type: 'keep', amount: 0 };
    }

    // If someone shared with you recently, return the favor
    const recentShares = this.memory.filter(obs =>
      obs.observed !== this.id &&
      obs.action.type === 'share' &&
      obs.action.target === this.id &&
      (step - obs.timestamp) < 5
    );

    if (recentShares.length > 0 && selfState.resources > 3) {
      // Share with someone who helped you
      const helper = recentShares[recentShares.length - 1].observed;
      return { type: 'share', amount: 1, target: helper };
    }

    // If doing well and someone else needs help, share
    if (selfState.resources > 5) {
      for (const [otherId, otherState] of others) {
        if (otherState.resources < 3 && otherState.alive) {
          return { type: 'share', amount: 1, target: otherId };
        }
      }
    }

    // Otherwise, gather/keep
    return { type: 'gather', amount: 1 };
  }

  /**
   * Execute an action and update state
   */
  execute(action: Action, worldState: Map<string, AgentState>): void {
    if (!this.state.alive) return;

    switch (action.type) {
      case 'gather':
        this.state.resources += action.amount;
        break;
      case 'share':
        if (action.target && worldState.has(action.target)) {
          const target = worldState.get(action.target)!;
          if (target.alive && this.state.resources >= action.amount) {
            this.state.resources -= action.amount;
            target.resources += action.amount;
          }
        }
        break;
      case 'keep':
        // Do nothing, keep resources
        break;
      case 'observe':
        // Just observe, no state change
        break;
    }

    // Survival cost
    this.state.resources -= 0.5;
    if (this.state.resources <= 0) {
      this.state.alive = false;
      this.state.resources = 0;
    }
  }

  /**
   * Observe another agent's action
   */
  observe(observedAgent: string, action: Action, timestamp: number): void {
    this.memory.push({
      observer: this.id,
      observed: observedAgent,
      action,
      timestamp
    });

    // Keep memory bounded
    if (this.memory.length > 50) {
      this.memory.shift();
    }
  }
}

/**
 * Bottom-Up Cooperation Simulation - World
 *
 * Simple world where agents interact. We observe what happens.
 */

import { Agent, Action, Observation, AgentState } from './Agent.js';

export interface Interaction {
  actor: string;
  action: Action;
  witnesses: string[];
  step: number;
}

export interface WorldEvent {
  type: 'action' | 'death' | 'birth';
  step: number;
  data: any;
}

/**
 * Simple world where agents interact
 */
export class World {
  agents: Map<string, Agent> = new Map();
  events: WorldEvent[] = [];
  step = 0;

  constructor() {
    // Start with 3 agents
    this.addAgent('alice', 8);
    this.addAgent('bob', 8);
    this.addAgent('charlie', 8);
  }

  addAgent(id: string, resources: number): void {
    this.agents.set(id, new Agent(id, resources));
    this.events.push({
      type: 'birth',
      step: this.step,
      data: { id, resources }
    });
  }

  /**
   * Run one step of the simulation
   */
  tick(): void {
    this.step++;

    // Each agent decides and acts
    const actions = new Map<string, Action>();

    for (const [id, agent] of this.agents) {
      if (!agent.state.alive) continue;

      // Get current world state for decision making
      const worldStates = new Map<string, AgentState>();
      for (const [otherId, otherAgent] of this.agents) {
        worldStates.set(otherId, { ...otherAgent.state });
      }

      const action = agent.decide({
        selfState: { ...agent.state },
        others: worldStates,
        step: this.step
      });

      actions.set(id, action);

      // Everyone observes the action (simplified - full observability)
      for (const [observerId, observerAgent] of this.agents) {
        if (observerId !== id && observerAgent.state.alive) {
          observerAgent.observe(id, action, this.step);
        }
      }
    }

    // Execute all actions
    for (const [id, action] of actions) {
      const agent = this.agents.get(id);
      if (agent && agent.state.alive) {
        const worldStates = new Map<string, AgentState>();
        for (const [otherId, otherAgent] of this.agents) {
          worldStates.set(otherId, { ...otherAgent.state });
        }

        agent.execute(action, worldStates);

        this.events.push({
          type: 'action',
          step: this.step,
          data: { actor: id, action }
        });
      }
    }

    // Check for deaths
    for (const [id, agent] of this.agents) {
      if (!agent.state.alive && agent.state.resources === 0) {
        this.events.push({
          type: 'death',
          step: this.step,
          data: { id }
        });
      }
    }
  }

  /**
   * Run simulation for N steps
   */
  run(steps: number): void {
    for (let i = 0; i < steps; i++) {
      this.tick();

      // Check if everyone is dead
      const aliveCount = Array.from(this.agents.values()).filter(a => a.state.alive).length;
      if (aliveCount === 0) break;
    }
  }

  /**
   * Get current state
   */
  getState(): Map<string, AgentState> {
    const state = new Map<string, AgentState>();
    for (const [id, agent] of this.agents) {
      state.set(id, { ...agent.state });
    }
    return state;
  }

  /**
   * Get history of actions
   */
  getHistory(): Interaction[] {
    const interactions: Interaction[] = [];

    for (const event of this.events) {
      if (event.type === 'action') {
        const witnesses = Array.from(this.agents.keys())
          .filter(id => id !== event.data.actor);

        interactions.push({
          actor: event.data.actor,
          action: event.data.action,
          witnesses,
          step: event.step
        });
      }
    }

    return interactions;
  }

  /**
   * Get cooperation events (sharing actions)
   */
  getCooperationEvents(): Interaction[] {
    return this.getHistory().filter(i => i.action.type === 'share');
  }
}

